#include <iostream>
#include <algorithm>
using namespace std;
#define MAX_N 16
#define MAX_M 10
#define MAX_K 100000

struct Word {
    int letters[MAX_M];
    int cost;
};

bool compare(const Word &x, const Word &y) {
    if (x.cost != y.cost) return x.cost > y.cost;
    for (int i = 0; i < MAX_M; i++) {
        if (x.letters[i] != y.letters[i]) return x.letters[i] < y.letters[i];
    }
    return false;
}

int main() {
    int N, M, K;
    cin >> N >> M >> K;
    int P[MAX_M][MAX_N];
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            cin >> P[i][j];
        }
    }
    Word words[N * N * N * N * N];
    int count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                for (int l = 0; l < N; l++) {
                    for (int m = 0; m < N; m++) {
                        words[count].letters[0] = i;
                        words[count].letters[1] = j;
                        words[count].letters[2] = k;
                        words[count].letters[3] = l;
                        words[count].letters[4] = m;
                        words[count].cost = P[0][i] + P[1][j] + P[2][k] + P[3][l] + P[4][m];
                        count++;
                    }
                }
            }
        }
    }
    sort(words, words + count, compare);
    for (int i = 0; i < M; i++) {
        cout << (char)(words[K - 1].letters[i] + 'a');
    }
    cout << endl;
    return 0;
}

