import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Word implements Comparable<Word> {
        int[] letters;
        int cost;
        public Word(int[] letters, int cost) {
            this.letters = letters;
            this.cost = cost;
        }
        @Override
        public int compareTo(Word o) {
            if (cost != o.cost) return o.cost - cost;
            for (int i = 0; i < letters.length; i++) {
                if (letters[i] != o.letters[i]) return letters[i] - o.letters[i];
            }
            return 0;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int K = sc.nextInt();
        int[][] P = new int[M][N];
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                P[i][j] = sc.nextInt();
            }
        }
        Word[] words = new Word[(int) Math.pow(N, M)];
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    for (int l = 0; l < N; l++) {
                        for (int m = 0; m < N; m++) {
                            int[] letters = {i, j, k, l, m};
                            int cost = P[0][i] + P[1][j] + P[2][k] + P[3][l] + P[4][m];
                            words[count++] = new Word(letters, cost);
                        }
                    }
                }
            }
        }
        Arrays.sort(words);
        for (int i = 0; i < M; i++) {
            System.out.print((char) (words[K - 1].letters[i] + 'a'));
        }
        System.out.println();
    }
}

